def test_unsubscribe_returns_false_if_not_found():
    bus = EventBus()
    assert bus.unsubscribe('x', lambda e: None) == False

def test_middleware_filters_event():
    bus = EventBus()
    class BlockMiddleware(Middleware):
        def process(self, event):
            if event.data.get('blocked'):
                return None
            return event
    bus.add_middleware(BlockMiddleware())
    results = []
    bus.subscribe('x', lambda e: results.append(1))
    bus.emit(Event('x', {'blocked': True}))
    bus.emit(Event('x', {'blocked': False}))
    assert results == [1]
